// exchangeQuotes.js
const axios = require('axios');

class BetfairExchange {
  constructor(appKey, username, password) {
    this.appKey = appKey;
    this.username = username;
    this.password = password;
    this.sessionToken = null;
  }

  async login() {
    try {
      const response = await axios.post(
        'https://identitysso.betfair.com/api/login',
        {},
        {
          headers: {
            'X-Application': this.appKey,
            'Content-Type': 'application/x-www-form-urlencoded'
          },
          auth: {
            username: this.username,
            password: this.password
          }
        }
      );
      this.sessionToken = response.data.token;
      return this.sessionToken;
    } catch (error) {
      console.error('Errore login:', error.response?.data || error.message);
      throw error;
    }
  }

  async getFootballMatches() {
    if (!this.sessionToken) await this.login();
    
    try {
      // Prima otteniamo i mercati delle partite di calcio
      const response = await axios.post(
        'https://api.betfair.com/exchange/betting/rest/v1.0/listMarketCatalogue/',
        {
          filter: {
            eventTypeIds: ['1'], // 1 = Calcio
            marketTypeCodes: ['MATCH_ODDS'], // Quote partita
            marketBettingTypes: ['ODDS'],
            marketCountries: ['IT'], // Filtro per Italia, puoi cambiarlo
            marketStartTime: {
              from: new Date().toISOString()
            }
          },
          maxResults: 10,
          marketProjection: ['EVENT', 'RUNNER_DESCRIPTION']
        },
        {
          headers: {
            'X-Application': this.appKey,
            'X-Authentication': this.sessionToken,
            'Content-Type': 'application/json'
          }
        }
      );
      
      return response.data;
    } catch (error) {
      console.error('Errore recupero partite:', error.response?.data || error.message);
      throw error;
    }
  }

  async getMarketOdds(marketId) {
    if (!this.sessionToken) await this.login();

    try {
      const response = await axios.post(
        'https://api.betfair.com/exchange/betting/rest/v1.0/listMarketBook/',
        {
          marketIds: [marketId],
          priceProjection: {
            priceData: ['EX_BEST_OFFERS'],
            virtualise: true
          }
        },
        {
          headers: {
            'X-Application': this.appKey,
            'X-Authentication': this.sessionToken,
            'Content-Type': 'application/json'
          }
        }
      );

      return response.data;
    } catch (error) {
      console.error('Errore recupero quote:', error.response?.data || error.message);
      throw error;
    }
  }
}

// Esempio di utilizzo
async function main() {
  const betfair = new BetfairExchange(
    'LZaNDBMfDOrUsTmX', // La tua DELAY Application Key
    'antonioaltieri565@outlook.it',
    'Avellino1!'
  );

  try {
    // 1. Ottieni le partite disponibili
    const matches = await betfair.getFootballMatches();
    console.log('Partite disponibili:', matches.map(m => ({
      nome: m.event.name,
      marketId: m.marketId,
      data: m.event.openDate
    })));

    // 2. Prendi il marketId della prima partita come esempio
    if (matches.length > 0) {
      const marketId = matches[0].marketId;
      const odds = await betfair.getMarketOdds(marketId);
      
      // Mostra le quote back e lay
      odds[0].runners.forEach(runner => {
        console.log(`\nQuote per ${runner.runnerName}:`);
        console.log('Back (Puntate):', runner.ex.availableToBack.map(b => b.price));
        console.log('Lay (Bancate):', runner.ex.availableToLay.map(l => l.price));
      });
    }
  } catch (error) {
    console.error('Errore:', error);
  }
}

main();